const xml = $input.first().json.data || $input.first().json;
const text = typeof xml === 'string' ? xml : JSON.stringify(xml);

// Extract URLs from sitemap XML
const urlRegex = /<loc>([^<]+)<\/loc>/g;
const urls = [];
let match;
while ((match = urlRegex.exec(text)) !== null) {
  urls.push(match[1]);
}

// Filter out non-page URLs
const pageUrls = urls.filter(u => 
  !u.includes('sitemap') && 
  !u.endsWith('.xml') &&
  !u.endsWith('.txt')
);

return pageUrls.map(url => ({ json: { url } }));

const items = $input.all();
const results = [];

for (const item of items) {
  const html = item.json.data || '';
  const url = item.json.url || '';

  // Extract title
  const titleMatch = html.match(/<title>([^<]*)<\/title>/);
  const title = titleMatch ? titleMatch[1] : 'MISSING';

  // Extract meta description
  const descMatch = html.match(/<meta\s+name="description"\s+content="([^"]*)"/);
  const description = descMatch ? descMatch[1] : 'MISSING';

  // Count H1 tags
  const h1Matches = html.match(/<h1[\s>]/g);
  const h1Count = h1Matches ? h1Matches.length : 0;

  // Extract H1 content
  const h1ContentMatch = html.match(/<h1[^>]*>([^<]*)<\/h1>/);
  const h1Content = h1ContentMatch ? h1ContentMatch[1].trim() : 'MISSING';

  // Check images without alt
  const imgMatches = [...html.matchAll(/<img\s[^>]*>/g)];
  const imgsWithoutAlt = imgMatches.filter(m => !(/alt="[^"]+"/.test(m[0])));

  // Check for schema.org
  const hasSchema = html.includes('application/ld+json');

  // Check for canonical
  const hasCanonical = html.includes('rel="canonical"');

  // Check OG tags
  const hasOgTitle = html.includes('property="og:title"');
  const hasOgDesc = html.includes('property="og:description"');
  const hasOgImage = html.includes('property="og:image"');

  // Check internal links
  const internalLinks = [...html.matchAll(/href="(\/[^"]*)"/g)].map(m => m[1]);
  const uniqueInternalLinks = [...new Set(internalLinks)];

  // Build issues list
  const issues = [];
  if (title === 'MISSING') issues.push('Missing <title> tag');
  else if (title.length > 90) issues.push(`Title too long (${title.length} chars)`);
  else if (title.length < 20) issues.push(`Title too short (${title.length} chars)`);

  if (description === 'MISSING') issues.push('Missing meta description');
  else if (description.length > 170) issues.push(`Meta description too long (${description.length} chars)`);
  else if (description.length < 50) issues.push(`Meta description too short (${description.length} chars)`);

  if (h1Count === 0) issues.push('Missing H1 tag');
  else if (h1Count > 1) issues.push(`Multiple H1 tags (${h1Count})`);

  if (imgsWithoutAlt.length > 0) issues.push(`${imgsWithoutAlt.length} image(s) without alt text`);
  if (!hasSchema) issues.push('Missing Schema.org JSON-LD');
  if (!hasCanonical) issues.push('Missing canonical URL');
  if (!hasOgTitle) issues.push('Missing og:title');
  if (!hasOgImage) issues.push('Missing og:image');
  if (uniqueInternalLinks.length < 2) issues.push('Low internal linking (fewer than 2 internal links)');

  results.push({
    json: {
      url,
      title,
      titleLength: title.length,
      description: description.substring(0, 100) + (description.length > 100 ? '...' : ''),
      descriptionLength: description.length,
      h1: h1Content,
      h1Count,
      imagesTotal: imgMatches.length,
      imagesWithoutAlt: imgsWithoutAlt.length,
      hasSchema,
      hasCanonical,
      hasOgTitle,
      hasOgDesc,
      hasOgImage,
      internalLinkCount: uniqueInternalLinks.length,
      issues,
      issueCount: issues.length,
      status: issues.length === 0 ? 'PASS' : issues.length <= 2 ? 'WARN' : 'FAIL'
    }
  });
}

return results;

const items = $input.all();

const pages = items.map(i => i.json);
const totalPages = pages.length;
const passCount = pages.filter(p => p.status === 'PASS').length;
const warnCount = pages.filter(p => p.status === 'WARN').length;
const failCount = pages.filter(p => p.status === 'FAIL').length;

// Calculate score
const maxIssues = totalPages * 10; // 10 possible checks per page
const totalIssues = pages.reduce((sum, p) => sum + p.issueCount, 0);
const score = Math.round(((maxIssues - totalIssues) / maxIssues) * 100);

// Collect all issues
const allIssues = pages
  .filter(p => p.issues.length > 0)
  .map(p => `\n**${p.url}** (${p.status})\n${p.issues.map(i => `  - ${i}`).join('\n')}`)
  .join('\n');

// Page summary table
const summary = pages.map(p => 
  `| ${p.url.replace('https://greenplanetgardening.eu', '')} | ${p.status} | ${p.titleLength} | ${p.descriptionLength} | ${p.h1Count} | ${p.imagesWithoutAlt}/${p.imagesTotal} |`
).join('\n');

const report = `# SEO Guardian Report\n\n**Date:** ${new Date().toISOString().split('T')[0]}\n**Score:** ${score}/100\n**Pages:** ${totalPages} total — ${passCount} pass, ${warnCount} warn, ${failCount} fail\n\n## Summary\n\n| Page | Status | Title Len | Desc Len | H1s | Imgs No Alt |\n|------|--------|-----------|----------|-----|-------------|\n${summary}\n\n## Issues Found\n${allIssues || '\nNo issues found! All pages pass SEO checks.'}\n`;

const hasCriticalIssues = failCount > 0;
const hasAnyIssues = totalIssues > 0;

return [{
  json: {
    report,
    score,
    totalPages,
    passCount,
    warnCount,
    failCount,
    totalIssues,
    hasCriticalIssues,
    hasAnyIssues,
    pages
  }
}];

const seoReport = $('Generate Report').first().json;
const psData = $input.first().json;

// Extract Lighthouse scores
const categories = psData.lighthouseResult?.categories || {};
const performance = Math.round((categories.performance?.score || 0) * 100);
const seo = Math.round((categories.seo?.score || 0) * 100);
const accessibility = Math.round((categories.accessibility?.score || 0) * 100);

// Core Web Vitals
const audits = psData.lighthouseResult?.audits || {};
const lcp = audits['largest-contentful-paint']?.displayValue || 'N/A';
const cls = audits['cumulative-layout-shift']?.displayValue || 'N/A';
const fid = audits['max-potential-fid']?.displayValue || 'N/A';

const fullReport = `${seoReport.report}\n## Lighthouse Scores (Mobile)\n\n| Metric | Score |\n|--------|-------|\n| Performance | ${performance}/100 |\n| SEO | ${seo}/100 |\n| Accessibility | ${accessibility}/100 |\n\n## Core Web Vitals\n\n| Metric | Value |\n|--------|-------|\n| LCP (Largest Contentful Paint) | ${lcp} |\n| CLS (Cumulative Layout Shift) | ${cls} |\n| FID (Max Potential First Input Delay) | ${fid} |\n`;

return [{
  json: {
    ...seoReport,
    report: fullReport,
    lighthouse: { performance, seo, accessibility },
    coreWebVitals: { lcp, cls, fid }
  }
}];

