const report = $('Merge with PageSpeed').first().json;
const claudeResponse = $input.first().json;

// Parse Claude's fix suggestions
let fixes = [];
try {
  const content = claudeResponse.content?.[0]?.text || '';
  const jsonMatch = content.match(/\[[\s\S]*\]/);
  if (jsonMatch) {
    fixes = JSON.parse(jsonMatch[0]);
  }
} catch (e) {
  fixes = [];
}

const hasFixableIssues = fixes.length > 0;

// Create GitHub issue body
const issueBody = `## Weekly SEO Guardian Report\n\n**Score:** ${report.score}/100\n**Lighthouse:** Performance ${report.lighthouse?.performance || 'N/A'}/100 | SEO ${report.lighthouse?.seo || 'N/A'}/100 | Accessibility ${report.lighthouse?.accessibility || 'N/A'}/100\n\n### Pages: ${report.passCount} pass, ${report.warnCount} warn, ${report.failCount} fail\n\n${fixes.length > 0 ? '### Suggested Fixes\n\n' + fixes.map((f, i) => `${i + 1}. **[${f.priority}]** \`${f.file}\`: ${f.issue}\n   Fix: ${f.fix}`).join('\n\n') : '### No fixes needed — site is healthy!'}\n\n---\n*Auto-generated by [Green Planet] SEO Guardian on ${new Date().toISOString().split('T')[0]}*`;

return [{
  json: {
    ...report,
    fixes,
    hasFixableIssues,
    issueTitle: `[SEO Guardian] Weekly Report — Score: ${report.score}/100 (${new Date().toISOString().split('T')[0]})`,
    issueBody
  }
}];

const report = $('Merge with PageSpeed').first().json;

return [{
  json: {
    status: 'healthy',
    score: report.score,
    message: `SEO Guardian: All pages healthy. Score: ${report.score}/100. Lighthouse: Perf ${report.lighthouse?.performance || 'N/A'}, SEO ${report.lighthouse?.seo || 'N/A'}, A11y ${report.lighthouse?.accessibility || 'N/A'}.`,
    report: report.report
  }
}];
